import React, { useState } from 'react';

interface Movie {
  id: number;
  title: string;
  image: string;
}

const MovieList: React.FC = () => {
  const [movies] = useState<Movie[]>([
    {
      id: 1,
      title: 'Inception',
      image: 'https://images.unsplash.com/photo-1542206395-9feb3edaa68f?w=400',
    },
    {
      id: 2,
      title: 'Interstellar',
      image: 'https://images.unsplash.com/photo-1542206395-9feb3edaa68f?w=400',
    },
    {
      id: 3,
      title: 'The Dark Knight',
      image: 'https://images.unsplash.com/photo-1542206395-9feb3edaa68f?w=400',
    },
  ]);

  return (
    <div className="grid grid-cols-1 sm:grid-cols-2 md:grid-cols-3 gap-6">
      {movies.map((movie) => (
        <div key={movie.id} className="bg-white rounded-xl shadow-md overflow-hidden">
          <img src={movie.image} alt={movie.title} className="w-full h-48 object-cover" />
          <div className="p-4">
            <h2 className="text-lg font-bold text-gray-800">{movie.title}</h2>
            <button className="mt-2 px-4 py-2 rounded-lg bg-blue-600 text-white hover:bg-blue-500 transition">
              Watch Now
            </button>
          </div>
        </div>
      ))}
    </div>
  );
};

export default MovieList;
